// auth.interceptor.ts - Interceptor para agregar Authorization
import { Injectable } from '@angular/core';
import { HttpInterceptor, HttpRequest, HttpHandler } from '@angular/common/http';

@Injectable()
export class AuthInterceptor implements HttpInterceptor {
  intercept(req: HttpRequest<any>, next: HttpHandler) {
    const credentials = btoa('admin:admin123');
    const authReq = req.clone({
      headers: req.headers.set(
        'Authorization', 
        `Basic ${credentials}`
      )
    });
    return next.handle(authReq);
  }
}

// customer-list.component.ts - Componente de ejemplo
export class CustomerListComponent implements OnInit {
  customers: CustomerResponse[] = [];
  loading = false;
  error: string | null = null;

  constructor(
    private customerService: CustomerService,
    private snackBar: MatSnackBar
  ) {}

  ngOnInit() {
    this.loadCustomers();
  }

  loadCustomers() {
    this.loading = true;
    this.customerService.findAll().subscribe(
      data => {
        this.customers = data;
        this.loading = false;
      },
      error => {
        this.error = 'Error loading customers';
        this.loading = false;
        this.snackBar.open('Error loading customers', 'Close');
      }
    );
  }

  deleteCustomer(id: number) {
    if (confirm('Are you sure?')) {
      this.customerService.delete(id).subscribe(
        () => {
          this.loadCustomers();
          this.snackBar.open('Customer deleted', 'Close');
        },
        error => {
          this.snackBar.open('Error deleting customer', 'Close');
        }
      );
    }
  }
}
